package com.example.app.ui;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.fragment.app.FragmentActivity;

import com.example.app.R;
import com.example.app.auth.BiometricAuthManager;

public class LoginActivity extends AppCompatActivity {
    private EditText passwordInput;
    private CheckBox biometricCheckbox;
    private Button loginButton;
    private Button biometricLoginButton;
    private BiometricAuthManager biometricAuthManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        biometricAuthManager = new BiometricAuthManager(this);

        passwordInput = findViewById(R.id.passwordInput);
        biometricCheckbox = findViewById(R.id.biometricCheckbox);
        loginButton = findViewById(R.id.loginButton);
        biometricLoginButton = findViewById(R.id.biometricLoginButton);

        biometricCheckbox.setChecked(biometricAuthManager.isBiometricEnabled());

        biometricCheckbox.setOnCheckedChangeListener((buttonView, isChecked) -> {
            biometricAuthManager.setBiometricEnabled(isChecked);
            if (!isChecked) {
                biometricAuthManager.clearAuthenticationState();
            }
        });

        loginButton.setOnClickListener(v -> performPasswordLogin());

        biometricLoginButton.setOnClickListener(v -> {
            if (!biometricAuthManager.isBiometricEnabled()) {
                Toast.makeText(this, "Enable biometric login first.", Toast.LENGTH_SHORT).show();
                return;
            }
            biometricAuthManager.authenticate(this, new BiometricAuthManager.AuthCallback() {
                @Override
                public void onSuccess() {
                    navigateToHome();
                }

                @Override
                public void onError(@NonNull String error) {
                    Toast.makeText(LoginActivity.this, error, Toast.LENGTH_SHORT).show();
                }

                @Override
                public void onUnavailable(@NonNull String reason) {
                    Toast.makeText(LoginActivity.this, reason, Toast.LENGTH_SHORT).show();
                }
            });
        });

        if (biometricAuthManager.isBiometricEnabled() && biometricAuthManager.isAuthenticated()) {
            navigateToHome();
            return;
        }
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (biometricAuthManager.isBiometricEnabled() && biometricAuthManager.isAuthenticated()) {
            navigateToHome();
        }
    }

    private void performPasswordLogin() {
        String password = passwordInput.getText().toString().trim();
        if (TextUtils.isEmpty(password)) {
            Toast.makeText(this, "Enter your password.", Toast.LENGTH_SHORT).show();
            return;
        }

        boolean passwordValid = validatePassword(password);
        if (passwordValid) {
            biometricAuthManager.setAuthenticated(true);
            navigateToHome();
        } else {
            Toast.makeText(this, "Invalid password.", Toast.LENGTH_SHORT).show();
        }
    }

    private boolean validatePassword(String password) {
        return "password123".equals(password);
    }

    private void navigateToHome() {
        Intent intent = new Intent(this, HomeActivity.class);
        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
}

